INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00743', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '社會企業與傳統商業企業的差異，在於價值與目的。社會企業的價值是社會關懷，不以追求利潤最大化， 而是採取企業注重效率的經營方式，賺錢以實踐解除弱勢困境的目的。社會企業的性質屬於下列何種團體？', '["第一部門", "第二部門", "第三部門", "初級團體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00744', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '食物銀行概念源自國外，其運作是熱心民眾以捐出食物或物資的方式，透過食物銀行等平台，交到需要者 的手裡。「家扶基金會」從2007年起，即透過與超商、賣場合作，建構扶助弱勢家庭的濟助免飢安全防護 網。綜上所述，「家扶基金會」應是下列何種團體？', '["參考團體", "初級團體", "財團法人", "社團法人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00745', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '為了凝聚政治意志的形成，人民往往會組成各式團體，如政黨、利益團體等。下列關於政黨和利益團體的 敘述，何者正確？', '["政黨及利益團體均是為了勝選而組成的團體", "利益團體是因共同的政治理想所組成的團體", "為了影響政策，利益團體常提名候選人參選", "政黨所關注的議題常常較利益團體來得廣泛"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00746', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '國際組織依據地理位置、會員資格、組織功能等，可分成許多種類。我國參與的「世界貿易組織」，下列敘 述何者錯誤？', '["全球性國際組織", "區域性國際組織", "政府間國際組織", "專門性國際組織"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00747', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '依我國憲法規定，選舉權的行使採普通、平等、直接、無記名四項原則。下列敘述何者錯誤？', '["婦女在第一次世界大戰前沒有投票權是違反平等原則", "民國85年起，我國由投票選出總統屬於直接原則", "任何人不得強制選民公開其選票，是屬於無記名原則", "選民在投票時，不需書寫自己的姓名屬於無記名原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00748', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '如何建立統治正當性與合法性是現代民主國家的重要課題，下列何者不是現代民主政治運作的重要基礎？', '["國家元首必須由公民直選產生", "保障人民擁有集會結社之權利", "確保媒體專業自主與新聞自由", "選舉過程應公平、公正及公開"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00749', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '大志在某鎮公所擔任課長職務，每逢選舉期間總是提醒自己應依法行政，秉持行政中立原則，依我國現行 法規，大志從事下列那些行為將違反行政中立的要求？', '["受現任鎮長的推薦而申請加入某政黨", "接受某政黨的徵召投入下屆鎮長選舉", "擔任現任鎮長競選連任總部的總幹事", "謝絕任一鎮長候選人進入鎮公所拜票"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00750', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '「利益團體」係指人民基於共同理念或利益所組成的團體。「政黨」則指一群具有共同政治意志、目標或利 益的人，為取得政治權力及政治職位，從事政治活動以實現其理想，而結合的政治性團體。關於政黨與利 益團體之比較，下列何者正確？', '["利益團體主要透過提名參選人影響公共政策，增進自身利益", "利益團體不同於政黨，無法透過遊說、陳情、媒體、助選、示威遊行等方式表達訴求", "政黨關注多面性之議題，並匯集選民各類意見進而實現執政目標", "政黨可區分為功能型（自利型）與倡議型（公益型）兩大類"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00751', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '內閣制的國會無任一政黨取得過半席位時，由二個以上政黨所聯合組成的政府，稱為「聯合內閣」（Coalition cabinet）。關於聯合內閣（Coalitioncabinet）制度之敘述，下列何者錯誤？', '["內閣較不穩定，並有倒閣的危機", "不同政黨間政策責任劃分不明", "不同政黨間意見統合，係最完美的政治型態", "可避免少數政府的情況，避免政府運作出現癱瘓"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00752', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '民主國家常見的選舉制度有多數決制、比例代表制及混合制，其中混合制又可分為聯立制與並立制。下列 有關於並立制的敘述，何者正確？', '["該選舉制度的區域選舉與政黨比例代表席次分開計算", "該選舉制度較有利於大黨，且容易產生超額當選的情況", "該制度較聯立制更容易產生黨內當選席次相互排擠現象", "無黨籍候選人無法透過此選舉制度成為國會議員"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
